    public static string Camelize(this string input)
    {
        return PascalizeCore(input, lowercaseFirst: true);
    }

    /// <summary>
    /// Shared core for Pascalize/Camelize. Uses a single StringBuilder pass
    /// over regex matches to avoid per-match Substring and ToUpper allocations.
    /// </summary>
    private static string PascalizeCore(string input, bool lowercaseFirst)
    {
        var matches = WordPartsRegex().Matches(input);
        if (matches.Count == 0)
        {
            return input;
        }

        var sb = new StringBuilder(input.Length);
        for (var i = 0; i < matches.Count; i++)
        {
            var match = matches[i];
            var span = match.ValueSpan;
            if (span.Length == 0)
            {
                continue;
            }

            if (i == 0 && lowercaseFirst)
            {
                sb.Append(char.ToLowerInvariant(span[0]));
            }
            else
            {
                sb.Append(char.ToUpperInvariant(span[0]));
            }

            if (span.Length > 1)
            {
#if NET6_0_OR_GREATER
                sb.Append(span[1..]);
#else
                sb.Append(match.Value, 1, match.Value.Length - 1);
#endif
            }
        }

        return sb.ToString();
    }

